<?php
 namespace WPAICG\Images\Providers\OpenAI; use WP_Error; if (!defined('ABSPATH')) { exit; } class OpenAIImageUrlBuilder { const IMAGES_GENERATIONS_ENDPOINT = '/images/generations'; const IMAGES_EDITS_ENDPOINT = '/images/edits'; public static function build(string $operation = 'images/generations', array $params = []): string|WP_Error { $base_url = !empty($params['base_url']) ? rtrim($params['base_url'], '/') : 'https://api.openai.com'; $api_version = !empty($params['api_version']) ? $params['api_version'] : 'v1'; if (empty($base_url)) { return new WP_Error("missing_base_url_openai_image", __('OpenAI Base URL is required for images.', 'gpt3-ai-content-generator')); } if (empty($api_version)) { return new WP_Error("missing_api_version_openai_image", __('OpenAI API Version is required for images.', 'gpt3-ai-content-generator')); } $endpoint = match ($operation) { 'images/generations' => self::IMAGES_GENERATIONS_ENDPOINT, 'images/edits' => self::IMAGES_EDITS_ENDPOINT, default => null, }; if ($endpoint === null) { return new WP_Error('unsupported_operation_openai_image', sprintf(__('Operation "%s" not supported for OpenAI Image URL Builder.', 'gpt3-ai-content-generator'), esc_html($operation))); } $version_segment = '/' . trim($api_version, '/'); if (strpos($base_url, $version_segment) !== false) { return $base_url . $endpoint; } else { return $base_url . $version_segment . $endpoint; } } } 